{
  "premium_report": {
    "report_title": "프리미엄 사주 리포트",
    "version": "v1.0",
    "sections": [
      {
        "section_id": "section_1",
        "category": "overall",
        "title": "프리미엄 사주 스토리",
        "headline": "아이디어를 차분히 다듬어 실제로 연결하는 사람이 바로 당신입니다",
        "summary_lines": [
          "아이디어를 실제로 옮길 때 여러 선택지를 살피며 흐름을 조정하는 편입니다.",
          "관계에서는 말과 생각의 순서를 다듬으며 소통의 효과를 높이는 것이 중요합니다.",
          "현재 흐름은 성과를 꾸준히 쌓되 일정한 리듬으로 판단을 정리하는 쪽으로 움직이고 있습니다."
        ],
        "core_insight": "당신은 아이디어를 실제로 옮길 때 여러 선택지를 동시에 살피는 편이고, 하나의 기준에만 의존하기보다 상황에 맞춰 흐름을 조금씩 조정합니다. 그래서 일을 진행할 때도 방향을 먼저 확정하기보다 다양한 가능성을 열어 두고 차분히 확인하는 습관이 강합니다. 지금 흐름은 성과를 쌓는 것을 목표로 하되 말과 생각의 순서를 다듬어 소통의 효과를 높이는 쪽으로 움직이고 있습니다. 이런 방식은 주변 사람과의 관계에서 신뢰를 쌓고 재정 관리에도 도움을 주는 편이라, 작은 변화가 큰 차이를 만드는 흐름을 만듭니다. 지금 흐름이 지속되면 직장이나 가정에서의 협력도 더 매끄럽게 흘러가고, 중요한 순간에 스트레스가 덜 느껴질 가능성이 큽니다.",
        "strength": "당신은 아이디어를 실제로 구현하는 데 필요한 실무 감각이 뛰어나고 상황에 맞춰 흐름을 조정하는 능력이 강점으로 작용합니다.",
        "risk": "다른 사람과의 협력에서 방향을 자주 바꿔야 하는 상황이 생길 때가 있어, 중요한 시점에 결정을 내리는 데 다소 시간이 걸릴 수 있습니다.",
        "action_points": [
          "하루를 시작하기 전에 오늘의 최우선 목표를 한 문장으로 정리하고, 이를 기준으로 움직이세요",
          "의사결정 시점에는 최소 2개의 대안과 그에 따른 결과를 천천히 비교한 뒤 최종 선택을 고정해 두세요",
          "주변 사람과의 대화는 흐름을 나누기보단 먼저 무엇을 전달하고자 하는지 말의 순서를 미리 생각하고 말하세요"
        ],
        "action_note": "작은 습관 하나를 꾸준히 지키면 큰 차이가 생깁니다. 지금의 흐름에 맞춰 자신을 잘 돌보고, 변화에 따른 루트를 천천히 만들어 가세요."
      }
    ]
  }
}
